proof fn phi_4_parse_high_bit_result_greater_than_one(s: Seq<u8>)
    requires
        s.len() > 0,
        s[0] as u8 >= 0x80,
        UnsignedLEB128.spec_parse(s).is_some(),
    ensures
        UnsignedLEB128.spec_parse(s).unwrap().1 > 1,
{
    UnsignedLEB128.lemma_spec_parse_non_zero(s);
}

proof fn phi_5_parse_value_fits_consumed_bits(s: Seq<u8>, n: int, v: UInt)
    requires
        s.len() > 0,
        UnsignedLEB128.spec_parse(s) == Some((n, v)),
    ensures
        n >= 1,
    decreases s.len(),
{
    if is_high_8_bit_set!(s[0]) {
        if let Some((n2, v2)) = UnsignedLEB128.spec_parse(s.drop_first()) {
            phi_5_parse_value_fits_consumed_bits(s.drop_first(), n2, v2);
        }
    }
}
